\subsection*{Esercizio 1: Dominio di Funzioni}
Determinare il dominio delle seguenti funzioni reali di variabile reale:
\begin{enumerate}[a)]
    \item $f(x) = \sqrt{x^2 - 4}$ (4 pt)
    \item $g(x) = \frac{1}{x^2 - 9}$ (2 pt)
    \item $h(x) = \log(x+3)$ (3 pt)
\end{enumerate}

\subsection*{Esercizio 2: Classificazione di Funzioni}
Si consideri la funzione $f(x) = x^3 - x$. 

Stabilire se la funzione è pari, dispari o né pari né dispari. Giustificare la risposta. (7 pt)
\subsection*{Esercizio 3: Limiti di Funzioni}
Calcolare il seguente limite:
$$ \lim_{x \to 2} \frac{x^2 - 4}{x - 2} $$ (7 pt)
\subsection*{Esercizio 4: Derivate}
Determinare la derivata prima delle seguenti funzioni:
\begin{enumerate}[a)]
    \item $f(x) = 3x^4 - 2x^2 + 5$
    \item $g(x) = \sin(x) \cdot e^x$
\end{enumerate}

\subsection*{Esercizio 5: Studio di Funzione (Punti Critici)}
Determinare i punti critici della funzione $f(x) = x^3 - 6x^2 + 5$. (7 pt)

